/**
 * useBrowserNotification
 *
 * Handles native browser Push Notification permission request and display.
 *
 * Usage:
 *   const { requestPermission, showNotification } = useBrowserNotification();
 *
 *   // Request once after login:
 *   useEffect(() => { requestPermission(); }, [currentUserId]);
 *
 *   // Show when a SignalR notification arrives and the tab is not visible:
 *   showNotification(title, body, { tag: notifId });
 */
import { useCallback } from 'react';

export interface BrowserNotificationOptions {
  tag?:  string;
  icon?: string;
  /** Deep-link path inside the app (e.g. /tickets/{id}#chat). Clicking the notification navigates here. */
  actionUrl?: string;
}

export function useBrowserNotification() {
  /**
   * Request browser notification permission.
   * Safe to call multiple times — only shows the prompt once.
   * Returns true if permission is (or was already) granted.
   */
  const requestPermission = useCallback(async (): Promise<boolean> => {
    if (!('Notification' in window)) {
      console.warn('[🔔 BrowserNotification] Notification API not supported in this browser/context');
      return false;
    }
    if (Notification.permission === 'granted')  return true;
    if (Notification.permission === 'denied') {
      console.warn('[🔔 BrowserNotification] Permission previously DENIED — user must reset via browser settings');
      return false;
    }

    console.log('[🔔 BrowserNotification] Requesting permission…');
    const result = await Notification.requestPermission();
    console.log('[🔔 BrowserNotification] Permission result:', result);
    return result === 'granted';
  }, []);

  /**
   * Show a browser notification.
   * Always shows regardless of tab visibility so the user gets notified
   * even while actively working. Clicking the notification focuses the
   * window and optionally navigates to actionUrl.
   */
  const showNotification = useCallback(
    (title: string, body: string, options: BrowserNotificationOptions = {}) => {
      if (!('Notification' in window)) {
        console.warn('[🔔 BrowserNotification] showNotification skipped — API not available');
        return;
      }
      if (Notification.permission !== 'granted') {
        console.warn(
          '[🔔 BrowserNotification] showNotification skipped — permission:',
          Notification.permission,
          '(call requestPermission() first)',
        );
        return;
      }
      console.log('[🔔 BrowserNotification] Firing OS notification:', title);

      const n = new Notification(title, {
        body,
        icon: options.icon ?? '/favicon.ico',
        tag:  options.tag,
      });

      n.onclick = () => {
        window.focus();
        if (options.actionUrl) {
          // Use the app's base path for GitHub Pages deployment
          const base = (import.meta.env.BASE_URL || '/').replace(/\/$/, '');
          window.location.href = base + options.actionUrl;
        }
        n.close();
      };
    },
    []
  );

  return { requestPermission, showNotification };
}
