import { UUID, Timestamps } from './common';

/**
 * Settings Models
 * Types and interfaces for user settings and preferences
 */

// ============================================================================
// User Settings
// ============================================================================

export interface UserSettings extends Timestamps {
  userId: UUID;
  profile: ProfileSettings;
  notifications: NotificationSettings;
  display: DisplaySettings;
  security: SecuritySettings;
  privacy: PrivacySettings;
}

// ============================================================================
// Profile Settings
// ============================================================================

export interface ProfileSettings {
  fullName: string;
  email?: string;          // optional — not every user has an email address
  emailVerified: boolean;
  phone?: string;
  bio?: string;
  avatar?: string;
  position?: string;
  department?: string;
}

// ============================================================================
// Notification Settings
// ============================================================================

export interface NotificationSettings {
  email: NotificationChannelSettings;
  push: NotificationChannelSettings;
  sms: NotificationChannelSettings;
  doNotDisturb: DoNotDisturbSettings;
}

export interface NotificationChannelSettings {
  enabled: boolean;
  newAssignment: boolean;
  statusChange: boolean;
  slaWarning: boolean;
  slaBreach: boolean;
  comment: boolean;
  approval: boolean;
  dailyDigest: boolean;
  weeklyReport: boolean;
}

export interface DoNotDisturbSettings {
  enabled: boolean;
  startTime: string; // HH:mm format (e.g., "22:00")
  endTime: string; // HH:mm format (e.g., "08:00")
  overrideForCritical: boolean;
}

// ============================================================================
// Display Settings
// ============================================================================

export interface DisplaySettings {
  theme: Theme;
  fontSize: FontSize;
  density: Density;
  language: Language;
  dateFormat: DateFormat;
  timeFormat: TimeFormat;
}

export enum Theme {
  Light = 'light',
  Dark = 'dark',
  Auto = 'auto',
}

export enum FontSize {
  Small = 'small',
  Medium = 'medium',
  Large = 'large',
}

export enum Density {
  Comfortable = 'comfortable',
  Compact = 'compact',
}

export enum Language {
  Vietnamese = 'vi',
  English = 'en',
}

export enum DateFormat {
  DDMMYYYY = 'DD/MM/YYYY',
  MMDDYYYY = 'MM/DD/YYYY',
  YYYYMMDD = 'YYYY-MM-DD',
}

export enum TimeFormat {
  Format24 = '24h',
  Format12 = '12h',
}

// ============================================================================
// Security Settings
// ============================================================================

export interface SecuritySettings {
  twoFactorEnabled: boolean;
  sessionTimeout: number; // in minutes
  lastPasswordChange?: string;
  passwordExpiryDays: number;
}

export interface ChangePasswordRequest {
  currentPassword: string;
  newPassword: string;
  confirmPassword: string;
}

// ============================================================================
// Privacy Settings
// ============================================================================

export interface PrivacySettings {
  profileVisibility: ProfileVisibility;
  showOnlineStatus: boolean;
  showEmail: boolean;
  showPhone: boolean;
  allowDataCollection: boolean;
  allowAnalytics: boolean;
}

export enum ProfileVisibility {
  Public = 'public',
  Team = 'team',
  Private = 'private',
}

// ============================================================================
// System Settings (Admin Only)
// ============================================================================

export interface SystemSettings extends Timestamps {
  general: GeneralSystemSettings;
  sla: SLASystemSettings;
  notifications: SystemNotificationSettings;
  security: SystemSecuritySettings;
}

export interface GeneralSystemSettings {
  systemName: string;
  timezone: string;
  defaultLanguage: Language;
  defaultDateFormat: DateFormat;
  autoAssignTasks: boolean;
  autoSendEmails: boolean;
  maintenanceMode: boolean;
}

export interface SLASystemSettings {
  autoEscalate: boolean;
  priorities: SLAPrioritySettings[];
}

export interface SLAPrioritySettings {
  priority: string;
  responseTime: number; // in minutes
  resolutionTime: number; // in minutes
  warningBefore: number; // in minutes
}

export interface SystemNotificationSettings {
  emailEnabled: boolean;
  smsEnabled: boolean;
  pushEnabled: boolean;
  smtpHost?: string;
  smtpPort?: number;
  smtpUser?: string;
  smsProvider?: string;
}

export interface SystemSecuritySettings {
  passwordMinLength: number;
  passwordRequireUppercase: boolean;
  passwordRequireLowercase: boolean;
  passwordRequireNumbers: boolean;
  passwordRequireSymbols: boolean;
  passwordExpiryDays: number;
  maxLoginAttempts: number;
  sessionTimeout: number;
}

// ============================================================================
// Utility Functions
// ============================================================================

export const getThemeLabel = (theme: Theme): string => {
  switch (theme) {
    case Theme.Light:
      return 'Sáng';
    case Theme.Dark:
      return 'Tối';
    case Theme.Auto:
      return 'Tự động';
    default:
      return theme;
  }
};

export const getFontSizeLabel = (fontSize: FontSize): string => {
  switch (fontSize) {
    case FontSize.Small:
      return 'Nhỏ';
    case FontSize.Medium:
      return 'Trung bình';
    case FontSize.Large:
      return 'Lớn';
    default:
      return fontSize;
  }
};

export const getDensityLabel = (density: Density): string => {
  switch (density) {
    case Density.Comfortable:
      return 'Thoải mái';
    case Density.Compact:
      return 'Gọn';
    default:
      return density;
  }
};

export const getLanguageLabel = (language: Language): string => {
  switch (language) {
    case Language.Vietnamese:
      return 'Tiếng Việt';
    case Language.English:
      return 'English';
    default:
      return language;
  }
};

export const getProfileVisibilityLabel = (visibility: ProfileVisibility): string => {
  switch (visibility) {
    case ProfileVisibility.Public:
      return 'Công khai';
    case ProfileVisibility.Team:
      return 'Nhóm';
    case ProfileVisibility.Private:
      return 'Riêng tư';
    default:
      return visibility;
  }
};

/**
 * Validate password strength
 */
export const validatePassword = (password: string, requirements?: SystemSecuritySettings): {
  valid: boolean;
  errors: string[];
} => {
  const errors: string[] = [];
  const minLength = requirements?.passwordMinLength || 8;

  if (password.length < minLength) {
    errors.push(`Mật khẩu phải có ít nhất ${minLength} ký tự`);
  }

  if (requirements?.passwordRequireUppercase && !/[A-Z]/.test(password)) {
    errors.push('Mật khẩu phải có ít nhất 1 chữ hoa');
  }

  if (requirements?.passwordRequireLowercase && !/[a-z]/.test(password)) {
    errors.push('Mật khẩu phải có ít nhất 1 chữ thường');
  }

  if (requirements?.passwordRequireNumbers && !/[0-9]/.test(password)) {
    errors.push('Mật khẩu phải có ít nhất 1 số');
  }

  if (requirements?.passwordRequireSymbols && !/[!@#$%^&*(),.?":{}|<>]/.test(password)) {
    errors.push('Mật khẩu phải có ít nhất 1 ký tự đặc biệt');
  }

  return {
    valid: errors.length === 0,
    errors,
  };
};

/**
 * Check if email is valid
 */
export const validateEmail = (email: string): boolean => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
};

/**
 * Check if phone number is valid (Vietnamese format)
 */
export const validatePhone = (phone: string): boolean => {
  const phoneRegex = /^(0|\+84)[0-9]{9,10}$/;
  return phoneRegex.test(phone.replace(/[\s-]/g, ''));
};
