/**
 * Help service facade.
 */

import {
  HelpCategory,
  SupportTicketCreate,
  ArticleFeedback,
} from '../../models/Help';
import { helpEndpoint } from './endpoint';

export const helpService = {
  getArticles: (category?: HelpCategory, featured?: boolean) =>
    helpEndpoint.getArticles(category, featured),

  getArticle: (slug: string) => helpEndpoint.getArticle(slug),

  submitFeedback: (feedback: ArticleFeedback) => helpEndpoint.submitFeedback(feedback),

  search: (query: string) => helpEndpoint.search(query),

  getFAQs: (category?: HelpCategory) => helpEndpoint.getFAQs(category),

  getWorkflows: () => helpEndpoint.getWorkflows(),

  getWorkflow: (type: 'ticket' | 'task' | 'incident') => helpEndpoint.getWorkflow(type),

  getVideos: (category?: HelpCategory) => helpEndpoint.getVideos(category),

  getCategories: () => helpEndpoint.getCategories(),

  submitSupportTicket: (ticket: SupportTicketCreate) =>
    helpEndpoint.submitSupportTicket(ticket),
};
