import React, { useEffect } from 'react';
import { useAppDispatch } from '../../store/hooks';
import { addToast } from '../../store/slices/uiSlice';
import { pushNotification } from '../../store/slices/notificationSlice';
import { useBrowserNotification } from '../../hooks/useBrowserNotification';

/**
 * Host-side bridge for events emitted by @linm/notification lifecycle.
 * Toast UI and /notifications page state stay in @linm/web-home.
 */
export const HomeShellEffects: React.FC = () => {
  const dispatch = useAppDispatch();
  const { showNotification } = useBrowserNotification();

  useEffect(() => {
    const onToast = (e: Event) => {
      const { title, message, priority } = (e as CustomEvent<{
        title: string;
        message: string;
        priority?: string;
      }>).detail;
      const toastType =
        priority === 'CRITICAL' ? 'error' : priority === 'HIGH' ? 'warning' : 'info';
      dispatch(addToast({ message: `${title}: ${message}`, type: toastType }));
    };

    const onBrowser = (e: Event) => {
      const { title, message, id, actionUrl } = (e as CustomEvent<{
        title: string;
        message: string;
        id?: string;
        actionUrl?: string;
      }>).detail;
      showNotification(title, message, { tag: id, actionUrl });
    };

    const onReceived = (e: Event) => {
      dispatch(pushNotification((e as CustomEvent).detail));
    };

    window.addEventListener('linm:notification:toast', onToast);
    window.addEventListener('linm:notification:browser', onBrowser);
    window.addEventListener('linm:notification:received', onReceived);
    return () => {
      window.removeEventListener('linm:notification:toast', onToast);
      window.removeEventListener('linm:notification:browser', onBrowser);
      window.removeEventListener('linm:notification:received', onReceived);
    };
  }, [dispatch, showNotification]);

  return null;
};
