/**
 * AboutTab — Displays build version, environment, and app metadata.
 *
 * Build info is injected at CI build time via Vite env vars:
 *   VITE_APP_VERSION, VITE_BUILD_NUMBER, VITE_BUILD_SHA, VITE_BUILD_DATE
 *
 * In local dev these fall back to placeholder values defined in appSettings.
 */

import React, { useState, useCallback } from 'react';
import { appSettings } from '../../../config/appSettings';
import { companyBrandingService } from '../../../services/companyBranding';
import styles from './AboutTab.module.css';

// ── Helpers ──────────────────────────────────────────────────────────────────

function formatBuildDate(iso: string): string {
  try {
    return new Intl.DateTimeFormat('vi-VN', {
      dateStyle: 'medium',
      timeStyle: 'short',
      timeZone: 'Asia/Ho_Chi_Minh',
    }).format(new Date(iso));
  } catch {
    return iso;
  }
}

function copyToClipboard(text: string) {
  navigator.clipboard?.writeText(text).catch(() => undefined);
}

// ── Component ─────────────────────────────────────────────────────────────────

export const AboutTab: React.FC = () => {
  const { build, isProduction, appName } = appSettings;
  const branding = companyBrandingService.get();
  const logoSrc = branding?.logoUrl ?? `${import.meta.env.BASE_URL}icons/logo-128.png`;
  const [copied, setCopied] = useState<string | null>(null);

  const handleCopy = useCallback((value: string, key: string) => {
    copyToClipboard(value);
    setCopied(key);
    setTimeout(() => setCopied(null), 1500);
  }, []);

  const fullVersion = `v${build.version} (build #${build.number})`;
  const buildDateFormatted = formatBuildDate(build.date);
  const isDevBuild = build.version.includes('-dev') || build.number === 'local';

  // Structured rows for detail table
  const detailRows: { label: string; value: string; copyKey?: string }[] = [
    { label: 'Phiên bản',       value: `v${build.version}`,   copyKey: 'version' },
    { label: 'Build #',         value: `#${build.number}`,    copyKey: 'number' },
    { label: 'Git commit',      value: build.sha,              copyKey: 'sha' },
    { label: 'Ngày build',      value: buildDateFormatted },
    { label: 'Môi trường',      value: isProduction ? 'Production' : 'Development' },
    // { label: 'API endpoint',    value: apiUrl,                  copyKey: 'api' },
  ];

  return (
    <div className={styles.aboutTab}>

      {/* ── App identity hero ── */}
      <div className={styles.identityCard}>
        <div className={styles.appLogo}>
          <img src={logoSrc} alt={branding?.name ?? appName} />
        </div>
        <div className={styles.appIdentity}>
          <h2 className={styles.appName}>{appName}</h2>
          <p className={styles.appSubtitle}>Hệ Thống Quản Trị Doanh Nghiệp</p>
          <div>
            <span className={styles.versionBadge}>
              <i className="fas fa-tag" /> {fullVersion}
            </span>
            <span className={`${styles.envBadge} ${isProduction && !isDevBuild ? styles.envProduction : styles.envDevelopment}`}>
              <i className={`fas fa-${isProduction && !isDevBuild ? 'check-circle' : 'code'}`} />
              {isProduction && !isDevBuild ? 'Production' : 'Development'}
            </span>
          </div>
        </div>
      </div>

      {/* ── Key metrics grid ── */}
      <div className={styles.infoGrid}>
        <div className={styles.infoCard}>
          <div className={`${styles.infoIcon} ${styles.iconBlue}`}>
            <i className="fas fa-code-branch" />
          </div>
          <div className={styles.infoContent}>
            <p className={styles.infoLabel}>Phiên bản</p>
            <p className={styles.infoValue}>v{build.version}</p>
            <p className={styles.infoSub}>Semantic version</p>
          </div>
        </div>

        <div className={styles.infoCard}>
          <div className={`${styles.infoIcon} ${styles.iconGreen}`}>
            <i className="fas fa-hammer" />
          </div>
          <div className={styles.infoContent}>
            <p className={styles.infoLabel}>Build số</p>
            <p className={styles.infoValue}>#{build.number}</p>
            <p className={styles.infoSub}>CI/CD run number</p>
          </div>
        </div>

        <div className={styles.infoCard}>
          <div className={`${styles.infoIcon} ${styles.iconPurple}`}>
            <i className="fab fa-git-alt" />
          </div>
          <div className={styles.infoContent}>
            <p className={styles.infoLabel}>Git commit</p>
            <p className={styles.infoValue}>{build.sha}</p>
            <p className={styles.infoSub}>Source code snapshot</p>
          </div>
        </div>

        <div className={styles.infoCard}>
          <div className={`${styles.infoIcon} ${styles.iconOrange}`}>
            <i className="fas fa-calendar-alt" />
          </div>
          <div className={styles.infoContent}>
            <p className={styles.infoLabel}>Ngày build</p>
            <p className={styles.infoValue} style={{ fontFamily: 'inherit', fontSize: '0.9rem' }}>
              {buildDateFormatted}
            </p>
            <p className={styles.infoSub}>Giờ Việt Nam</p>
          </div>
        </div>
      </div>

      {/* ── Detail table ── */}
      <div className={styles.detailCard}>
        <div className={styles.detailCardHeader}>
          <i className={`fas fa-info-circle ${styles.detailCardIcon}`} />
          <h3 className={styles.detailCardTitle}>Thông tin chi tiết</h3>
        </div>
        <table className={styles.detailTable}>
          <tbody>
            {detailRows.map((row) => (
              <tr key={row.label}>
                <th>{row.label}</th>
                <td>
                  {row.value}
                  {row.copyKey && (
                    <button
                      className={styles.copyBtn}
                      title="Copy"
                      onClick={() => handleCopy(row.value, row.copyKey!)}
                    >
                      <i className={`fas ${copied === row.copyKey ? 'fa-check' : 'fa-copy'}`} />
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* ── Links ── */}
      <div className={styles.linksCard}>
        <div className={styles.linksHeader}>
          <i className={`fas fa-link ${styles.detailCardIcon}`} />
          <h3 className={styles.linksTitle}>Liên kết</h3>
        </div>
        <div className={styles.linksList}>
          <a
            className={styles.linkItem}
            href={`https://github.com/linm-soft/BVUB-NA.WebApp/commits/gh-pages`}
            target="_blank"
            rel="noopener noreferrer"
          >
            <span className={`${styles.linkIcon} ${styles.iconBlue}`}>
              <i className="fab fa-github" />
            </span>
            Lịch sử deploy (GitHub)
            <i className={`fas fa-external-link-alt ${styles.linkChevron}`} />
          </a>
          <div className={styles.linkDivider} />
          <button
            className={styles.linkItem}
            onClick={() => handleCopy(fullVersion + ' | SHA: ' + build.sha + ' | ' + build.date, 'all')}
          >
            <span className={`${styles.linkIcon} ${styles.iconGreen}`}>
              <i className={`fas ${copied === 'all' ? 'fa-check' : 'fa-clipboard'}`} />
            </span>
            {copied === 'all' ? 'Đã copy!' : 'Copy thông tin build (báo cáo lỗi)'}
            <i className={`fas fa-chevron-right ${styles.linkChevron}`} />
          </button>
        </div>
      </div>

    </div>
  );
};
