import React, { useState } from 'react';
import { FAQ } from '../../../models/Help';
import styles from './FAQList.module.css';

interface FAQListProps {
  faqs: FAQ[];
}

export const FAQList: React.FC<FAQListProps> = ({ faqs }) => {
  const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());

  const toggleFAQ = (id: string) => {
    const newExpanded = new Set(expandedIds);
    if (newExpanded.has(id)) {
      newExpanded.delete(id);
    } else {
      newExpanded.add(id);
    }
    setExpandedIds(newExpanded);
  };

  return (
    <div className={styles.faqList}>
      {faqs.map((faq) => {
        const isExpanded = expandedIds.has(faq.id);
        
        return (
          <div
            key={faq.id}
            id={faq.id}
            className={`${styles.faqItem} ${isExpanded ? styles.expanded : ''}`}
          >
            <button
              className={styles.question}
              onClick={() => toggleFAQ(faq.id)}
            >
              <span className={styles.questionText}>{faq.question}</span>
              <span className={styles.icon}>{isExpanded ? '−' : '+'}</span>
            </button>
            
            {isExpanded && (
              <div className={styles.answer}>
                <p>{faq.answer}</p>
                
                {faq.relatedArticles && faq.relatedArticles.length > 0 && (
                  <div className={styles.related}>
                    <strong>Bài viết liên quan:</strong>
                    <ul>
                      {faq.relatedArticles.map((article, index) => (
                        <li key={index}>
                          <a href={`/help/articles/${article}`}>{article}</a>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
};
