import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useAppSelector } from '../../store/hooks';
import { getHomePath } from '@linm-soft/common-components';
import './NotFoundPage.css';

const NotFoundPage: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { isAuthenticated, user } = useAppSelector((state) => state.auth);

  const handleGoHome = () => {
    if (isAuthenticated) {
      navigate(
        getHomePath(user?.role, user?.package, user?.defaultMenuUrl, user?.packageDefaultUrl),
        { replace: true },
      );
    } else {
      navigate('/login', { replace: true });
    }
  };

  return (
    <div className="not-found-page">
      <div className="not-found-container">
        <div className="not-found-icon">🏥</div>
        <h1 className="not-found-code">404</h1>
        <h2 className="not-found-title">Trang không tìm thấy</h2>
        <p className="not-found-description">
          Trang <code>{location.pathname}</code> không tồn tại hoặc đã bị di chuyển.
        </p>
        <div className="not-found-actions">
          <button className="btn-primary" onClick={handleGoHome}>
            {isAuthenticated ? '🏠 Về trang chủ' : '🔐 Đăng nhập'}
          </button>
          <button className="btn-secondary" onClick={() => navigate(-1)}>
            ← Quay lại
          </button>
        </div>
      </div>
    </div>
  );
};

export default NotFoundPage;
