/**
 * ProfileTab Component
 * Profile settings with avatar upload
 */

import React, { useState } from 'react';
import { UserSettings, ProfileSettings, validateEmail, validatePhone } from '../../../models/Settings';
import { settingsService } from '../../../services/settingsService';
import { useAlert } from '../../../components/common/Alert';
import styles from './ProfileTab.module.css';

interface ProfileTabProps {
  settings: UserSettings;
  onSave: (settings: Partial<UserSettings>) => void;
  saving: boolean;
}

export const ProfileTab: React.FC<ProfileTabProps> = ({ settings, onSave, saving }) => {
  const alert = useAlert();
  const [profile, setProfile] = useState<ProfileSettings>(settings.profile);
  const [uploadingAvatar, setUploadingAvatar] = useState(false);
  const [errors, setErrors] = useState<Record<string, string>>({});

  const handleChange = (field: keyof ProfileSettings, value: string) => {
    setProfile((prev) => ({
      ...prev,
      [field]: value,
    }));
    
    // Clear error for this field
    if (errors[field]) {
      setErrors((prev) => {
        const newErrors = { ...prev };
        delete newErrors[field];
        return newErrors;
      });
    }
  };

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (!profile.fullName.trim()) {
      newErrors.fullName = 'Tên không được để trống';
    }

    // Email is optional; validate format only when provided
    if (profile.email && profile.email.trim() && !validateEmail(profile.email)) {
      newErrors.email = 'Email không hợp lệ';
    }

    if (profile.phone && !validatePhone(profile.phone)) {
      newErrors.phone = 'Số điện thoại không hợp lệ';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSave = () => {
    if (validate()) {
      onSave({ profile });
    }
  };

  const handleAvatarUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      setUploadingAvatar(true);
      const result = await settingsService.uploadAvatar(file);
      setProfile((prev) => ({
        ...prev,
        avatar: result.url,
      }));
      
      // Auto-save avatar
      onSave({
        profile: {
          ...profile,
          avatar: result.url,
        },
      });
    } catch (err: any) {
      alert.error(err.message || 'Không thể tải lên ảnh');
    } finally {
      setUploadingAvatar(false);
    }
  };

  const handleRequestEmailVerification = async () => {
    if (!profile.email) return;
    try {
      const result = await settingsService.requestEmailVerification(profile.email);
      alert.success(result.message);
    } catch (err: any) {
      alert.error(err.message || 'Không thể gửi email xác thực');
    }
  };

  return (
    <div className={styles.profileTab}>
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <h3 className={styles.cardTitle}>Thông tin cá nhân</h3>
          <p className={styles.cardDescription}>
            Cập nhật thông tin hồ sơ và ảnh đại diện của bạn
          </p>
        </div>

        <div className={styles.cardBody}>
          {/* Avatar Upload */}
          <div className={styles.avatarSection}>
            <label className={styles.label}>Ảnh đại diện</label>
            <div className={styles.avatarUpload}>
              <div className={styles.avatarPreview}>
                {profile.avatar ? (
                  <img src={profile.avatar} alt={profile.fullName} />
                ) : (
                  <div className={styles.avatarPlaceholder}>
                    <i className="fas fa-user"></i>
                  </div>
                )}
                {uploadingAvatar && (
                  <div className={styles.avatarLoading}>
                    <i className="fas fa-spinner fa-spin"></i>
                  </div>
                )}
              </div>
              <div className={styles.avatarActions}>
                <label htmlFor="avatar-upload" className={styles.uploadButton}>
                  <i className="fas fa-camera"></i> Thay đổi ảnh
                </label>
                <input
                  id="avatar-upload"
                  type="file"
                  accept="image/*"
                  onChange={handleAvatarUpload}
                  className={styles.fileInput}
                  disabled={uploadingAvatar}
                />
                <p className={styles.helpText}>JPG, PNG hoặc GIF. Tối đa 5MB.</p>
              </div>
            </div>
          </div>

          {/* Full Name */}
          <div className={styles.formGroup}>
            <label className={styles.label}>
              Họ và tên <span className={styles.required}>*</span>
            </label>
            <input
              type="text"
              className={`${styles.input} ${errors.fullName ? styles.inputError : ''}`}
              value={profile.fullName}
              onChange={(e) => handleChange('fullName', e.target.value)}
            />
            {errors.fullName && <span className={styles.errorText}>{errors.fullName}</span>}
          </div>

          {/* Email */}
          <div className={styles.formGroup}>
            <label className={styles.label}>Email</label>
            <div className={styles.inputGroup}>
              <input
                type="email"
                className={`${styles.input} ${errors.email ? styles.inputError : ''}`}
                value={profile.email || ''}
                onChange={(e) => handleChange('email', e.target.value)}
                placeholder="VD: name@example.com"
              />
              {profile.email && !settings.profile.emailVerified && (
                <button
                  type="button"
                  className={styles.verifyButton}
                  onClick={handleRequestEmailVerification}
                >
                  Xác thực
                </button>
              )}
            </div>
            {profile.email && (
              settings.profile.emailVerified ? (
                <span className={styles.successText}>
                  <i className="fas fa-check-circle"></i> Email đã được xác thực
                </span>
              ) : (
                <span className={styles.warningText}>
                  <i className="fas fa-exclamation-triangle"></i> Email chưa được xác thực
                </span>
              )
            )}
            {errors.email && <span className={styles.errorText}>{errors.email}</span>}
          </div>

          {/* Phone */}
          <div className={styles.formGroup}>
            <label className={styles.label}>Số điện thoại</label>
            <input
              type="tel"
              className={`${styles.input} ${errors.phone ? styles.inputError : ''}`}
              value={profile.phone || ''}
              onChange={(e) => handleChange('phone', e.target.value)}
              placeholder="VD: 0912345678"
            />
            {errors.phone && <span className={styles.errorText}>{errors.phone}</span>}
          </div>

          {/* Position */}
          <div className={styles.formGroup}>
            <label className={styles.label}>Chức vụ</label>
            <input
              type="text"
              className={styles.input}
              value={profile.position || ''}
              onChange={(e) => handleChange('position', e.target.value)}
              placeholder="VD: Chuyên viên IT"
            />
          </div>

          {/* Department */}
          <div className={styles.formGroup}>
            <label className={styles.label}>Phòng ban</label>
            <input
              type="text"
              className={styles.input}
              value={profile.department || ''}
              readOnly
              placeholder="VD: Phòng IT"
            />
          </div>

          {/* Bio */}
          <div className={styles.formGroup}>
            <label className={styles.label}>Giới thiệu</label>
            <textarea
              className={styles.textarea}
              value={profile.bio || ''}
              onChange={(e) => handleChange('bio', e.target.value)}
              rows={4}
              placeholder="Viết một vài dòng giới thiệu về bạn..."
            />
          </div>
        </div>

        <div className={styles.cardFooter}>
          <button
            onClick={handleSave}
            className={styles.saveButton}
            disabled={saving}
          >
            {saving ? (
              <>
                <i className="fas fa-spinner fa-spin"></i> Đang lưu...
              </>
            ) : (
              <>
                <i className="fas fa-save"></i> Lưu thay đổi
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};
