import React, { useEffect, useRef } from 'react';
import { hasValidAuthToken } from '@linm-soft/common-components';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { ToastProvider, ReduxToastContainer } from './components/common/Toast';
import { AlertProvider } from './components/common/Alert';
import { ProtectedRoute } from './components/auth/ProtectedRoute';
import { PublicRoute } from './components/auth/PublicRoute';
import { AppLayout } from '@linm-soft/common-components';
import { HomeShellEffects } from './components/layout/HomeShellEffects';
import LoginPage from './pages/LoginPage';
import SettingsPage from './pages/SettingsPage';
import NotificationsPage from './pages/NotificationsPage';
import MessagesPage from './pages/MessagesPage';
import NotFoundPage from './pages/NotFoundPage';
import { HelpCenterPage } from './pages/HelpCenterPage';
import { FAQPage } from './pages/FAQPage';
import { ContactPage } from './pages/ContactPage';
import { InstallAppGuidePage } from './pages/InstallAppGuidePage';
import { NotificationGuidePage } from './pages/NotificationGuidePage';
import UnauthorizedPage from './pages/UnauthorizedPage';
import SessionExpiredPage from './pages/SessionExpiredPage';
import { appSettings } from './config/appSettings';
import { registerRefreshSuccessCallback } from './services/api';
import { updateUserFromRefresh } from './store/slices/authSlice';
import { mapAuthUser } from './services/auth/mapper';
import { store } from './store/store';
import { companyBrandingService } from './services/companyBranding';
import { useAppSelector } from './store/hooks';

const CompanyBrandingSync: React.FC = () => {
  const companyId = useAppSelector((state) => state.auth.user?.companyId);
  const lastFetchedIdRef = useRef<string | null>(null);

  useEffect(() => {
    const pendingCode = localStorage.getItem('pending_company_code');
    if (pendingCode) {
      localStorage.removeItem('pending_company_code');
      companyBrandingService
        .fetchByCode(pendingCode, appSettings.apiUrl)
        .catch(() => { /* non-blocking */ });
    }
  }, []);

  useEffect(() => {
    if (!companyId || !hasValidAuthToken()) return;
    const stored = companyBrandingService.get();
    if (stored?.id === companyId) {
      lastFetchedIdRef.current = companyId;
      return;
    }
    if (lastFetchedIdRef.current === companyId) return;
    lastFetchedIdRef.current = companyId;
    companyBrandingService
      .fetchById(companyId, appSettings.apiUrl)
      .catch(() => { /* non-blocking */ });
  }, [companyId]);

  return null;
};

const App: React.FC = () => {
  const basename = import.meta.env.BASE_URL;

  useEffect(() => {
    registerRefreshSuccessCallback((raw) => {
      if (raw.user) {
        const updatedUser = mapAuthUser(raw.user as Parameters<typeof mapAuthUser>[0]);
        store.dispatch(updateUserFromRefresh(updatedUser));
      }
    });
  }, []);

  return (
    <AlertProvider>
      <ToastProvider>
        <ReduxToastContainer />
        <CompanyBrandingSync />
        <Router basename={basename} future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
          <Routes>
            <Route path="/login" element={<PublicRoute><LoginPage /></PublicRoute>} />
            <Route
              path="/"
              element={
                <ProtectedRoute>
                  <>
                    <HomeShellEffects />
                    <AppLayout />
                  </>
                </ProtectedRoute>
              }
            >
              <Route index element={null} />
              <Route path="settings" element={<SettingsPage />} />
              <Route path="notifications" element={<NotificationsPage />} />
              <Route path="messages" element={<MessagesPage />} />
              <Route path="messages/:entityType/:entityId" element={<MessagesPage />} />
              <Route path="help" element={<HelpCenterPage />} />
              <Route path="faq" element={<FAQPage />} />
              <Route path="contact" element={<ContactPage />} />
              <Route path="install-guide" element={<InstallAppGuidePage />} />
              <Route path="notification-guide" element={<NotificationGuidePage />} />
            </Route>
            <Route path="/unauthorized" element={<UnauthorizedPage />} />
            <Route path="/session-expired" element={<SessionExpiredPage />} />
            <Route path="*" element={<NotFoundPage />} />
          </Routes>
        </Router>
      </ToastProvider>
    </AlertProvider>
  );
};

export default App;
