import React, { useState, useEffect } from 'react';
import { useAppDispatch, useAppSelector } from '../../store/hooks';
import { login, clearError } from '../../store/slices/authSlice';
import { addToast } from '../../store/slices/uiSlice';
import styles from './LoginPage.module.css';
import { Button } from '../../components/common/Button';
import { Card } from '../../components/common/Card';
import { Input } from '../../components/common/Input';
import { ChangePasswordModal } from '../../components/auth/ForceChangePasswordSlideout';
import { companyBrandingService, CompanyBranding } from '../../services/companyBranding';

const LoginPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { loading, error, isAuthenticated, requirePasswordChange } = useAppSelector((state) => state.auth);

  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [branding, setBranding] = useState<CompanyBranding | null>(() => companyBrandingService.get());

  useEffect(() => {
    // Clear any previous errors when component mounts
    dispatch(clearError());
  }, [dispatch]);

  // Re-read branding in case it was fetched asynchronously after mount
  // (e.g. when Root-App captured a /company/{code} URL before redirecting here)
  useEffect(() => {
    setBranding(companyBrandingService.get());
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!username || !password) {
      dispatch(addToast({
        message: 'Vui lòng nhập tên đăng nhập và mật khẩu',
        type: 'error',
      }));
      return;
    }

    try {
      await dispatch(login({ username, password })).unwrap();
      dispatch(addToast({
        message: 'Đăng nhập thành công!',
        type: 'success',
      }));
      // Navigation will happen via useEffect
    } catch (error: any) {
      // Auth slice error state also shows inline form error
      const message = error instanceof Error ? error.message : 'Tên đăng nhập hoặc mật khẩu không đúng';
      dispatch(addToast({ message, type: 'error' }));
    }
  };

  return (
    <div className={styles.container}>
      <ChangePasswordModal isOpen={isAuthenticated && !!requirePasswordChange} isForced={true} />
      <Card className={styles.card}>
        <div className={styles.logo}>
          {branding?.logoUrl
            ? <img src={branding.logoUrl} alt={branding.name || 'Logo'} />
            : <img src={`${import.meta.env.BASE_URL}icons/logo-128.png`} alt="Linm-Soft" />
          }
        </div>
        {branding && <p className={styles.companyName}>{branding.name}</p>}
        <h1 className={styles.title}>LINM ERP</h1>
        <p className={styles.subtitle}>Hệ Thống Quản Trị Doanh Nghiệp</p>

        <form onSubmit={handleLogin} className={styles.form}>
          {error && (
            <div className={styles.errorMessage}>
              <i className="fas fa-exclamation-circle"></i>
              <span>{error}</span>
            </div>
          )}

          <div className={styles.inputGroup}>
            <label htmlFor="username">Tên đăng nhập</label>
            <Input
              id="username"
              type="text"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              placeholder="Nhập tên đăng nhập"
              required
              autoComplete="username"
              disabled={loading}
            />
          </div>

          <div className={styles.inputGroup}>
            <label htmlFor="password">Mật khẩu</label>
            <div className={styles.passwordWrapper}>
              <Input
                id="password"
                type={showPassword ? 'text' : 'password'}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Nhập mật khẩu"
                required
                autoComplete="current-password"
                disabled={loading}
                className={styles.passwordInput}
              />
              <button
                type="button"
                className={styles.togglePassword}
                onClick={() => setShowPassword((v) => !v)}
                tabIndex={-1}
                aria-label={showPassword ? 'Ẩn mật khẩu' : 'Hiện mật khẩu'}
              >
                <i className={showPassword ? 'fas fa-eye-slash' : 'fas fa-eye'}></i>
              </button>
            </div>
          </div>

          <Button type="submit" fullWidth loading={loading} disabled={!username || !password}>
            {loading ? 'Đang đăng nhập...' : 'Đăng nhập'}
          </Button>
        </form>

      </Card>
    </div>
  );
};

export default LoginPage;
