import React from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useNavTitle } from '@linm-soft/common-components';
import { MessagesPageParcelHost } from '../../components/parcels/MessagesPageParcelHost';

/** Route shell — inbox UI owned by @linm/message parcel. */
const MessagesPage: React.FC = () => {
  useNavTitle('Tin nhắn');
  const { entityType, entityId } = useParams<{ entityType?: string; entityId?: string }>();
  const navigate = useNavigate();

  return (
    <MessagesPageParcelHost
      entityType={entityType}
      entityId={entityId}
      onNavigate={(path) => navigate(path)}
    />
  );
};

export default MessagesPage;
